\displaystyle{\begin{aligned}
  \frac{{\frac{1}{k-1}-\frac{5}{k+1}}}{{4-\frac{1}{k+1}}} \amp = \frac{({\frac{1}{k-1}-\frac{5}{k+1}})\cdot{\left(k-1\right)\mathopen{}\left(k+1\right)}}{({4-\frac{1}{k+1}})\cdot{\left(k-1\right)\mathopen{}\left(k+1\right)}} \\
    \amp = \frac{{\frac{1}{k-1}\mathopen{}\left(k-1\right)\mathopen{}\left(k+1\right)-\frac{5}{k+1}\mathopen{}\left(k-1\right)\mathopen{}\left(k+1\right)}}{{4\mathopen{}\left(k-1\right)\mathopen{}\left(k+1\right)-\frac{1}{k+1}\mathopen{}\left(k-1\right)\mathopen{}\left(k+1\right)}} \\
    \amp = \frac{{k+1-5\mathopen{}\left(k-1\right)}}{{4\mathopen{}\left(k^{2}-1\right)-\left(k-1\right)}}, k \ne -1 \text{ and }  k \ne 1 \\
    \amp = \frac{{k+1-5k+5}}{{4k^{2}-4-k+1}}, k \ne -1 \text{ and }  k \ne 1 \\
    \amp = \frac{{-4k+6}}{{4k^{2}-k-3}}, k \ne -1 \text{ and }  k \ne 1 \\
    \amp = {-\frac{2\mathopen{}\left(2k-3\right)}{\left(4k+3\right)\mathopen{}\left(k-1\right)}, k\ne -1}
\end{aligned}
    }
